    for(int j=0; j<systemNN->sizeDataSystem; j++){
      systemNN->dataSystem[j] = 0.0;
    }

    fillMatrixesNN(systemNN->neuralNetwork, population->pop[i]);

    makeSimulationOfSignalNN(systemNN, trash, 0);
    fit[i] = systemNN->fit;

  }
}
